```javascript
$(document).ready(function() {
    var navbarLinks = $('.nav-link');

    $(document).on('click', function(event) {
        var isClickInside = $('#navbar').has(event.target).length !== 0;
        if (!isClickInside) {
            var navbarCollapsed = $('#navbarNavAltMarkup').hasClass('show');
            if (navbarCollapsed) {
                var navbarToggle = $('.navbar-toggler');
                navbarToggle.click();
            }
        }
    });

    navbarLinks.each(function() {
        $(this).on('click', function(event) {
            event.preventDefault();
            var target = $($(this).attr('href'));
            if (target.length) {
                var targetOffsetTop = target.offset().top;
                $('html, body').animate({
                    scrollTop: targetOffsetTop - 80
                }, 'slow');
                var navbarCollapsed = $('#navbarNavAltMarkup').hasClass('show');
                if (navbarCollapsed) {
                    var navbarToggle = $('.navbar-toggler');
                    navbarToggle.click();
                }
            }
        });
    });
});
```
